import{_ as e,a as i,b as a}from"./chunks/wordpress-application-layer-application-modules.l5P4PG6Q.js";import{_ as o,o as n,c as r,ag as l}from"./chunks/framework.BPmc_f4o.js";const b=JSON.parse('{"title":"Applications","description":"","frontmatter":{},"headers":[],"relativePath":"applications/applications.md","filePath":"applications/applications.md"}'),s={name:"applications/applications.md"};function p(d,t,c,h,u,g){return n(),r("div",null,[...t[0]||(t[0]=[l('<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="applications" tabindex="-1">Applications <a class="header-anchor" href="#applications" aria-label="Permalink to &quot;Applications&quot;">​</a></h1><p>An Application is the core unit of the Pro experience. Each application has its own API policy, users, modules, and output behavior. This lets you serve multiple clients from one WordPress install without mixing rules across clients.</p><p>You can create as many applications as you need. Each one is independent.</p><hr><h2 id="manage-applications" tabindex="-1">Manage Applications <a class="header-anchor" href="#manage-applications" aria-label="Permalink to &quot;Manage Applications&quot;">​</a></h2><p>The list view is the entry point for managing all your applications.</p><ul><li><strong>Create</strong> a new application with the add button.</li><li><strong>Enable / Disable</strong> an application with the toggle. A confirmation dialog requires you to type the application name before the change is applied — this prevents accidental deactivation of a live application.</li><li><strong>Delete</strong> an application permanently. A confirmation dialog requires you to type the application name before deletion proceeds.</li><li><strong>Open</strong> any application to access its editor and module configuration.</li></ul><p>When at least one application is enabled, unmatched requests are handled by route type:</p><ul><li><strong>Core WordPress routes</strong> can be blocked or redirected depending on your mode.</li><li><strong>Plugin routes</strong> can still be governed by route policy without being hard-bound to a single application.</li></ul><figure><img src="'+e+'" alt="Applications"><figcaption>Applications</figcaption></figure><hr><h2 id="configure-an-application" tabindex="-1">Configure an Application <a class="header-anchor" href="#configure-an-application" aria-label="Permalink to &quot;Configure an Application&quot;">​</a></h2><p>Each application has its own editor with two areas:</p><h3 id="settings-tab" tabindex="-1">Settings Tab <a class="header-anchor" href="#settings-tab" aria-label="Permalink to &quot;Settings Tab&quot;">​</a></h3><ul><li><strong>Title</strong> — display name used throughout the admin.</li><li><strong>Description</strong> — optional notes for your own reference.</li><li><strong>Enabled</strong> — activate or deactivate the application without deleting it.</li></ul><h3 id="control-modules" tabindex="-1">Control Modules <a class="header-anchor" href="#control-modules" aria-label="Permalink to &quot;Control Modules&quot;">​</a></h3><p>The Modules tab gives a compact overview and per-module toggle entry points.</p><ul><li>Use it to confirm which modules are active for the current application.</li><li>Jump directly to module-specific screens.</li><li>Keep noisy modules disabled on applications that do not need them.</li></ul><figure><img src="'+i+'" alt="Application Settings"><figcaption>Application Settings</figcaption></figure><h3 id="modules" tabindex="-1">Modules <a class="header-anchor" href="#modules" aria-label="Permalink to &quot;Modules&quot;">​</a></h3><p>Each module can be toggled on or off at the application level. A module must also be globally active to take effect. The editor shows a summary of the current configuration for each module and a direct link to its dedicated settings panel.</p><table tabindex="0"><thead><tr><th>Module</th><th>Description</th><th>Doc</th></tr></thead><tbody><tr><td><strong>Auth &amp; Rate Limiting</strong></td><td>Auth methods, allowed origins &amp; IPs, HTTP methods, users and per-user overrides</td><td><a href="/users/users.html">→ Auth &amp; Rate Limiting</a></td></tr><tr><td><strong>IP Filtering</strong></td><td>Additional application-scoped blocks: CIDR ranges, country blocking, retention time</td><td><a href="/ipsfilter/ipsfilter.html">→ IP Filtering</a></td></tr><tr><td><strong>Routes Policy</strong></td><td>Per-route auth, rate limit, disable, user restriction</td><td><a href="/routes/routes.html">→ Routes</a></td></tr><tr><td><strong>Properties &amp; Models</strong></td><td>Response transforms, per-property control, custom schemas</td><td><a href="/models/models.html">→ Properties &amp; Models</a></td></tr><tr><td><strong>Collections</strong></td><td>Per-page limits, drag-and-drop sort order</td><td><a href="/collections/collections.html">→ Collections</a></td></tr><tr><td><strong>Automations</strong></td><td>Event-driven workflows with conditions and actions</td><td><a href="/automations/automations.html">→ Automations</a></td></tr><tr><td><strong>Webhooks</strong></td><td>Outbound webhook entries with event triggers</td><td><a href="/webhooks/webhooks.html">→ Webhooks</a></td></tr><tr><td><strong>Emails</strong></td><td>Transactional email templates with SMTP</td><td><a href="/mails/mails.html">→ Emails</a></td></tr><tr><td><strong>WordPress Mode</strong></td><td>Applications-only mode, trusted IPs, emergency token</td><td><a href="/wordpress-mode/wordpress-mode.html">→ WordPress Mode</a></td></tr></tbody></table><figure><img src="'+a+'" alt="Application Modules"><figcaption>Application Modules</figcaption></figure><hr><h2 id="configure-auth-rate-limiting" tabindex="-1">Configure Auth &amp; Rate Limiting <a class="header-anchor" href="#configure-auth-rate-limiting" aria-label="Permalink to &quot;Configure Auth &amp; Rate Limiting&quot;">​</a></h2><p>See the dedicated <a href="/users/users.html">Auth &amp; Rate Limiting</a> page for full documentation of application-level defaults, the users list, and the user editor.</p><hr><h2 id="configure-ip-filtering" tabindex="-1">Configure IP Filtering <a class="header-anchor" href="#configure-ip-filtering" aria-label="Permalink to &quot;Configure IP Filtering&quot;">​</a></h2><p>Manages application-scoped IP blocking, layered on top of the <a href="/global-ip-filtering/global-ip-filtering.html">Global IP Filtering</a> module. Entries here only apply to this application.</p><ul><li><strong>Blacklist</strong> — listed IPs or CIDR ranges are blocked for this application. Configurable retention time.</li><li><strong>Country blocking</strong> — block requests by country using GeoIP data, scoped to this application.</li><li><strong>CIDR support</strong> — define ranges in addition to individual addresses.</li></ul><p>See the dedicated <a href="/ipsfilter/ipsfilter.html">IP Filtering</a> page for full documentation.</p><hr><h2 id="harden-with-applications-only-mode" tabindex="-1">Harden with Applications Only Mode <a class="header-anchor" href="#harden-with-applications-only-mode" aria-label="Permalink to &quot;Harden with Applications Only Mode&quot;">​</a></h2><p>If enabled in <a href="/wordpress-mode/wordpress-mode.html">WordPress Mode</a>, the installation behaves as application-first:</p><ul><li>Unmatched <strong>core</strong> REST requests are redirected according to your configured destination.</li><li>Unmatched <strong>plugin</strong> REST routes keep flowing through route-level controls.</li></ul><p>Use this mode when WordPress is strictly an API backend and you want non-application traffic redirected away.</p><hr><h2 id="plan-application-lifecycle-changes" tabindex="-1">Plan Application Lifecycle Changes <a class="header-anchor" href="#plan-application-lifecycle-changes" aria-label="Permalink to &quot;Plan Application Lifecycle Changes&quot;">​</a></h2><ul><li>Disabling an application preserves all settings and entries.</li><li>Deleting an application removes app ownership but can preserve related records for later reassignment workflows.</li><li>License expiry or pro deactivation can be handled with a guided fallback export flow. See <a href="/migration/migration.html">Migration &amp; Fallback</a>.</li></ul><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>Can multiple applications share the same origin?</strong></p><p>Yes. The firewall resolves the application through a combination of identification steps: authenticated user, client IP, origin header, and custom header. It never relies on origin alone, as the origin header can be spoofed. Multiple applications can share the same origin provided they are distinguished by another identifier.</p><p><strong>What happens when no application matches a request?</strong></p><p>For core routes, unmatched requests are blocked (or redirected in applications only mode). Plugin routes can still be handled via route policy.</p><p><strong>Can I test an application&#39;s policy before enabling it?</strong></p><p>Yes. The Routes module includes a Test panel that lets you fire live requests through the current policy without exposing it to real traffic.</p>',48)])])}const y=o(s,[["render",p]]);export{b as __pageData,y as default};
